import React, { useEffect, useState } from 'react';
import axios from 'axios';
import './UserAddress.css';

const UserAddress = ({ userId }) => {
    const [show, setShow] = useState(false);
    const [savedAddresses, setSavedAddresses] = useState([]);
    const [formData, setFormData] = useState({
        AddressLine1: '',
        AddressLine2: '',
        AddressLine3: '',
        postalCode: '',
        city: '',
        country: '',
        isDefault: false
    });
    const [editId, setEditId] = useState(null);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');

    useEffect(() => {
        fetchAddresses();
    }, [userId]);

    const fetchAddresses = async () => {
        setLoading(true);
        try {
            const response = await axios.get(`/api/users/${userId}`);
            setSavedAddresses(response.data.user.addresses);
        } catch (err) {
            setError('Failed to fetch addresses');
            console.error(err);
        } finally {
            setLoading(false);
        }
    };

    const handleInputChange = (e) => {
        const { name, value } = e.target;
        setFormData({
            ...formData,
            [name]: value,
        });
    };

    const handleSaveAddress = async () => {
        if (!formData.AddressLine1 || !formData.postalCode || !formData.city || !formData.country) {
            setError('Required fields are missing');
            return;
        }

        setLoading(true);
        try {
            if (editId) {
                await axios.put(`/api/users/${userId}/addresses/${editId}`, formData);
            } else {
                await axios.post(`/api/users/${userId}/addresses`, formData);
            }
            fetchAddresses();
            setShow(false);
            setFormData({
                AddressLine1: '',
                AddressLine2: '',
                AddressLine3: '',
                postalCode: '',
                city: '',
                country: '',
                isDefault: false
            });
            setEditId(null);
        } catch (err) {
            setError('Failed to save address');
            console.error(err);
        } finally {
            setLoading(false);
        }
    };

    const handleDeleteAddress = async (id) => {
        setLoading(true);
        try {
            await axios.delete(`/api/users/${userId}/addresses/${id}`);
            fetchAddresses();
        } catch (err) {
            setError('Failed to delete address');
            console.error(err);
        } finally {
            setLoading(false);
        }
    };

    const handleEditAddress = (address) => {
        setFormData(address);
        setEditId(address._id);
        setShow(true);
    };

    return (
        <div className='useraddress'>
            {loading && <p>Loading...</p>}
            {error && <p className='error'>{error}</p>}
            {/* Render the address list and form */}
            {/* ... (same as before) ... */}
        </div>
    );
};

export default UserAddress;
